import { Routes } from '@angular/router';

export const routes: Routes = [
  {
    path: '',
    loadComponent: () =>
      import('./manual-builder/manual-builder.component').then(
        (m) => m.ManualBuilderComponent,
      ),
  },
  {
    path: 'ai',
    loadComponent: () =>
      import('./ai-builder/ai-builder.component').then(
        (m) => m.AiBuilderComponent,
      ),
  },
  {
    path: 'build_resume',
    redirectTo: '',
    pathMatch: 'full',
  },
];
